import { Injectable } from "@angular/core";
import { CommonHttpModule } from "../../../providers/commonHttpModule";
import { MaClient } from "./client.model";
import { map, Observable } from "rxjs";

@Injectable({
  providedIn: "root"
})
export class ClientService {

  constructor(private http: CommonHttpModule) {

  }

  // method to send the data from db
  ClientDataToDB(data: MaClient): Observable<any> {
    const transformedData: MaClient = {
      ...data,
      status: data.status === true ? "Y" : "N"
    };
    return this.http.post("clients", transformedData).pipe(
      map((response) => {
        return response;
      })
    )
  }

  ClientDataFromDb(body: any): Observable<{total_count:number, data:MaClient[]}> {
    return this.http.post<{ total_count: number, data: MaClient[] }>("clientlist", body).pipe(
      map(response => {
        return response
      })
    );
  }

  VslListFromDb(body: any): Observable<any> {
    return this.http.post<any>("vessels-by-assignment", body).pipe(
      map(response => {
        return response;
      })
    );
  }


  


}